'use client'
import { cn, Slot } from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import type { LabelHTMLAttributes, ReactNode } from 'react'
import styles from './label.module.css'

export interface LabelProps extends LabelHTMLAttributes<HTMLLabelElement> {
  /** Renders into the child element (Slot composition) instead of a native `<label>`. */
  asChild?: boolean
  /** Shows a required marker after the label text. */
  required?: boolean
  /** Dims the label to match an associated disabled control. */
  disabled?: boolean
  children: ReactNode
  /** Override built-in strings (e.g. the required-marker accessible text). */
  labels?: { required?: string }
}

export function Label({
  asChild = false,
  required = false,
  disabled = false,
  className,
  children,
  labels,
  ...props
}: LabelProps) {
  const Comp = asChild ? Slot : 'label'
  const requiredText = labels?.required ?? t(builtin.label.required)

  const marker = required ? (
    <>
      <span className={styles['marker']} aria-hidden="true">
        *
      </span>
      <span className={styles['srOnly']}>{requiredText}</span>
    </>
  ) : null

  return (
    <Comp
      data-disabled={disabled ? '' : undefined}
      className={cn(styles['label'], className as string | undefined)}
      {...(props as Record<string, unknown>)}
    >
      {marker ? (
        <>
          {children}
          {marker}
        </>
      ) : (
        children
      )}
    </Comp>
  )
}

@layer cascivo.component {
  .label {
    display: inline-flex;
    align-items: center;
    gap: var(--cascivo-space-1);
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    font-weight: var(--cascivo-font-medium);
    line-height: var(--cascivo-leading-snug);
    color: var(--cascivo-color-text);

    &[data-disabled] {
      opacity: 0.5;
      cursor: not-allowed;
    }
  }

  .marker {
    color: var(--cascivo-color-destructive);
    line-height: var(--cascivo-leading-none);
  }

  .srOnly {
    position: absolute;
    inline-size: 1px;
    block-size: 1px;
    margin: -1px;
    padding: 0;
    border: 0;
    clip: rect(0 0 0 0);
    clip-path: inset(50%);
    overflow: hidden;
    white-space: nowrap;
  }
}

@media (forced-colors: active) {
  .label[data-disabled] {
    color: GrayText;
  }
}
